# fix-journey-upload-and-carousel-ui.ps1
# Fixes upload error handling (with local-preview fallback for testing) + image fit, adds chevron nav + thumbnail strip
$ErrorActionPreference = 'Stop'
Write-Host "Applying Journey upload + carousel UI fixes..." -ForegroundColor Cyan

Write-Host "Writing src\components\public\JourneySection.tsx"
$dir = Split-Path -Parent "src\components\public\JourneySection.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64JourneySection = @"

"@
[System.IO.File]::WriteAllBytes("src\components\public\JourneySection.tsx", [System.Convert]::FromBase64String($b64JourneySection))

Write-Host "Writing src\app\admin\(protected)\journey\JourneyManager.tsx"
$dir = Split-Path -Parent "src\app\admin\(protected)\journey\JourneyManager.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64JourneyManager = @"

"@
[System.IO.File]::WriteAllBytes("src\app\admin\(protected)\journey\JourneyManager.tsx", [System.Convert]::FromBase64String($b64JourneyManager))

Write-Host "Done. 2 files updated." -ForegroundColor Green